    # Calls {OCI::Wlms::WeblogicManagementServiceClient#update_wls_domain} and then waits for the {OCI::Wlms::Models::WlsDomain} acted upon
    # to enter the given state(s).
    #
    # @param [String] wls_domain_id The [OCID](https://docs.cloud.oracle.com/iaas/Content/General/Concepts/identifiers.htm) of the WebLogic domain.
    # @param [OCI::Wlms::Models::UpdateWlsDomainDetails] update_wls_domain_details The new details required to update the WebLogic domain.
    # @param [Array<String>] wait_for_states An array of states to wait on. These should be valid values for {OCI::Wlms::Models::WlsDomain#lifecycle_state}
    # @param [Hash] base_operation_opts Any optional arguments accepted by {OCI::Wlms::WeblogicManagementServiceClient#update_wls_domain}
    # @param [Hash] waiter_opts Optional arguments for the waiter. Keys should be symbols, and the following keys are supported:
    #   * max_interval_seconds: The maximum interval between queries, in seconds.
    #   * max_wait_seconds The maximum time to wait, in seconds
    #
    # @return [OCI::Response] A {OCI::Response} object with data of type {OCI::Wlms::Models::WlsDomain}
    def update_wls_domain_and_wait_for_state(wls_domain_id, update_wls_domain_details, wait_for_states = [], base_operation_opts = {}, waiter_opts = {})
      operation_result = @service_client.update_wls_domain(wls_domain_id, update_wls_domain_details, base_operation_opts)

      return operation_result if wait_for_states.empty?

      lowered_wait_for_states = wait_for_states.map(&:downcase)
      wait_for_resource_id = operation_result.data.id

      begin
        waiter_result = @service_client.get_wls_domain(wait_for_resource_id).wait_until(
          eval_proc: ->(response) { response.data.respond_to?(:lifecycle_state) && lowered_wait_for_states.include?(response.data.lifecycle_state.downcase) },
          max_interval_seconds: waiter_opts.key?(:max_interval_seconds) ? waiter_opts[:max_interval_seconds] : 30,
          max_wait_seconds: waiter_opts.key?(:max_wait_seconds) ? waiter_opts[:max_wait_seconds] : 1200
        )
        result_to_return = waiter_result

        return result_to_return
      rescue StandardError
        raise OCI::Errors::CompositeOperationError.new(partial_results: [operation_result])
      end
    end
    # rubocop:enable Metrics/CyclomaticComplexity, Metrics/AbcSize, Metrics/ParameterLists, Metrics/PerceivedComplexity
    # rubocop:enable Layout/EmptyLines
  end
